                                            <td className="px-6 py-0">
                                                {row.status === 'processing' ? (
                                                    <div className="flex-1 h-3 bg-slate-100 animate-pulse rounded"></div>
                                                ) : (
                                                    <input 
                                                        type="text" 
                                                        value={row.name} 
