  amount?: number;
  date?: string;
  recipient?: string;
  sender?: string;
  reason?: string;
}

export interface FileModel {
  id: string;
  name: string;
  user_id: string;
  version: number;
  lineage_id: string;
  is_active: boolean;

  fingerprint: {
    columnCount: number;
    delimiter: string;
    headerHash: string | null;
    dataTopology: string;      
  };

  mapping: {
    dateColumnIndex: number;
    descriptionColumnIndex: number;
    amountColumnIndex: number;
    typeColumnIndex?: number;
    skipRowsStart: number;
    skipRowsEnd: number;
    decimalSeparator: ',' | '.';
    thousandsSeparator: '.' | ',' | '';
  };

  parsingRules: {
    ignoredKeywords: string[]; 
    rowFilters: string[];      
    dateFormat?: string;
  };

  snippet?: string; // Novo campo para armazenar as primeiras linhas do arquivo
  createdAt: string;
  lastUsedAt?: string;
}

